import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, Package, DollarSign, Users, TrendingUp, 
  Plus, Edit, Trash2, X, Check, Clock, XCircle, LogOut 
} from 'lucide-react';
import { adminService } from '../services/api';

function AdminDashboard({ user, onLogout }) {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [dashboard, setDashboard] = useState(null);
  const [products, setProducts] = useState([]);
  const [sales, setSales] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [productForm, setProductForm] = useState({
    productName: '',
    description: '',
    price: '',
    commissionPercentage: '10',
  });

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'dashboard') {
        const response = await adminService.getDashboard();
        setDashboard(response.data);
      } else if (activeTab === 'products') {
        const response = await adminService.getProducts();
        setProducts(response.data);
      } else if (activeTab === 'sales') {
        const response = await adminService.getSales();
        setSales(response.data);
      }
    } catch (error) {
      console.error('Error loading data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateProduct = () => {
    setEditingProduct(null);
    setProductForm({
      productName: '',
      description: '',
      price: '',
      commissionPercentage: '10',
    });
    setShowProductModal(true);
  };

  const handleEditProduct = (product) => {
    setEditingProduct(product);
    setProductForm({
      productName: product.productName,
      description: product.description || '',
      price: product.price.toString(),
      commissionPercentage: product.commissionPercentage.toString(),
    });
    setShowProductModal(true);
  };

  const handleDeleteProduct = async (productId) => {
    if (window.confirm('Are you sure you want to deactivate this product?')) {
      try {
        await adminService.deleteProduct(productId);
        loadData();
      } catch (error) {
        alert('Error deleting product');
      }
    }
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingProduct) {
        await adminService.updateProduct(editingProduct.productId, productForm);
      } else {
        await adminService.createProduct(productForm);
      }
      setShowProductModal(false);
      loadData();
    } catch (error) {
      alert('Error saving product');
    }
  };

  const handleUpdateSaleStatus = async (saleId, status) => {
    try {
      await adminService.updateSaleStatus(saleId, status);
      loadData();
    } catch (error) {
      alert('Error updating sale status');
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amount);
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  const getStatusBadge = (status) => {
    const badges = {
      Completed: 'badge-success',
      Pending: 'badge-warning',
      Failed: 'badge-danger',
    };
    return badges[status] || 'badge-primary';
  };

  return (
    <div className="dashboard">
      <div className="sidebar">
        <div className="sidebar-logo">
          <h2>Sales ERP</h2>
          <p>Admin Panel</p>
        </div>

        <div className="sidebar-menu">
          <div
            className={`menu-item ${activeTab === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActiveTab('dashboard')}
          >
            <LayoutDashboard size={20} />
            Dashboard
          </div>
          <div
            className={`menu-item ${activeTab === 'products' ? 'active' : ''}`}
            onClick={() => setActiveTab('products')}
          >
            <Package size={20} />
            Products
          </div>
          <div
            className={`menu-item ${activeTab === 'sales' ? 'active' : ''}`}
            onClick={() => setActiveTab('sales')}
          >
            <DollarSign size={20} />
            Sales
          </div>
        </div>

        <div className="sidebar-footer">
          <div className="user-info">
            <p>{user.fullName}</p>
            <span>{user.email}</span>
          </div>
          <button className="btn btn-secondary" style={{ width: '100%' }} onClick={onLogout}>
            <LogOut size={16} />
            Logout
          </button>
        </div>
      </div>

      <div className="main-content">
        {activeTab === 'dashboard' && dashboard && (
          <>
            <div className="page-header">
              <h1>Dashboard</h1>
              <p>Welcome back, {user.fullName}!</p>
            </div>

            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon primary">
                    <Package size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Total Products</h3>
                  <p>{dashboard.stats.totalProducts}</p>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon success">
                    <DollarSign size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Total Revenue</h3>
                  <p>{formatCurrency(dashboard.stats.totalRevenue)}</p>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon warning">
                    <TrendingUp size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Total Sales</h3>
                  <p>{dashboard.stats.totalSales}</p>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon danger">
                    <Users size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Active Partners</h3>
                  <p>{dashboard.stats.activePartners}</p>
                </div>
              </div>
            </div>

            <div className="card">
              <div className="card-header">
                <h2>Top Partners</h2>
              </div>
              <div className="table-container">
                <table>
                  <thead>
                    <tr>
                      <th>Partner Name</th>
                      <th>Company</th>
                      <th>Total Sales</th>
                      <th>Revenue</th>
                      <th>Commission</th>
                    </tr>
                  </thead>
                  <tbody>
                    {dashboard.partners.map((partner) => (
                      <tr key={partner.partnerId}>
                        <td>{partner.partnerName}</td>
                        <td>{partner.partnerCompany || 'N/A'}</td>
                        <td>{partner.totalSales}</td>
                        <td>{formatCurrency(partner.totalRevenue)}</td>
                        <td>{formatCurrency(partner.totalCommission)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            <div className="card">
              <div className="card-header">
                <h2>Recent Sales</h2>
              </div>
              <div className="table-container">
                <table>
                  <thead>
                    <tr>
                      <th>Product</th>
                      <th>Partner</th>
                      <th>Buyer</th>
                      <th>Amount</th>
                      <th>Date</th>
                      <th>Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {dashboard.recentSales.map((sale) => (
                      <tr key={sale.saleId}>
                        <td>{sale.productName}</td>
                        <td>{sale.partnerName}</td>
                        <td>{sale.buyerName}</td>
                        <td>{formatCurrency(sale.saleAmount)}</td>
                        <td>{formatDate(sale.saleDate)}</td>
                        <td>
                          <span className={`badge ${getStatusBadge(sale.paymentStatus)}`}>
                            {sale.paymentStatus}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

        {activeTab === 'products' && (
          <>
            <div className="page-header">
              <div>
                <h1>Products</h1>
                <p>Manage your software products</p>
              </div>
              <button className="btn btn-primary" onClick={handleCreateProduct}>
                <Plus size={16} />
                Add Product
              </button>
            </div>

            <div className="card">
              <div className="table-container">
                {loading ? (
                  <div style={{ textAlign: 'center', padding: '48px' }}>Loading...</div>
                ) : products.length === 0 ? (
                  <div className="empty-state">
                    <Package size={64} />
                    <h3>No products yet</h3>
                    <p>Create your first product to get started</p>
                  </div>
                ) : (
                  <table>
                    <thead>
                      <tr>
                        <th>Product Name</th>
                        <th>Description</th>
                        <th>Price</th>
                        <th>Commission</th>
                        <th>Status</th>
                        <th>Created</th>
                        <th>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {products.map((product) => (
                        <tr key={product.productId}>
                          <td><strong>{product.productName}</strong></td>
                          <td>{product.description?.substring(0, 50)}...</td>
                          <td>{formatCurrency(product.price)}</td>
                          <td>{product.commissionPercentage}%</td>
                          <td>
                            <span className={`badge ${product.isActive ? 'badge-success' : 'badge-danger'}`}>
                              {product.isActive ? 'Active' : 'Inactive'}
                            </span>
                          </td>
                          <td>{formatDate(product.createdAt)}</td>
                          <td>
                            <button
                              className="btn btn-secondary"
                              style={{ marginRight: '8px', padding: '8px 12px' }}
                              onClick={() => handleEditProduct(product)}
                            >
                              <Edit size={14} />
                            </button>
                            <button
                              className="btn btn-danger"
                              style={{ padding: '8px 12px' }}
                              onClick={() => handleDeleteProduct(product.productId)}
                            >
                              <Trash2 size={14} />
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            </div>
          </>
        )}

        {activeTab === 'sales' && (
          <>
            <div className="page-header">
              <h1>All Sales</h1>
              <p>View and manage all sales transactions</p>
            </div>

            <div className="card">
              <div className="table-container">
                {loading ? (
                  <div style={{ textAlign: 'center', padding: '48px' }}>Loading...</div>
                ) : sales.length === 0 ? (
                  <div className="empty-state">
                    <DollarSign size={64} />
                    <h3>No sales yet</h3>
                    <p>Sales will appear here once partners make transactions</p>
                  </div>
                ) : (
                  <table>
                    <thead>
                      <tr>
                        <th>ID</th>
                        <th>Product</th>
                        <th>Partner</th>
                        <th>Buyer</th>
                        <th>Amount</th>
                        <th>Commission</th>
                        <th>Date</th>
                        <th>Status</th>
                        <th>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {sales.map((sale) => (
                        <tr key={sale.saleId}>
                          <td>#{sale.saleId}</td>
                          <td>{sale.productName}</td>
                          <td>{sale.partnerName}</td>
                          <td>{sale.buyerName}</td>
                          <td>{formatCurrency(sale.saleAmount)}</td>
                          <td>{formatCurrency(sale.commissionAmount)}</td>
                          <td>{formatDate(sale.saleDate)}</td>
                          <td>
                            <span className={`badge ${getStatusBadge(sale.paymentStatus)}`}>
                              {sale.paymentStatus}
                            </span>
                          </td>
                          <td>
                            {sale.paymentStatus === 'Pending' && (
                              <button
                                className="btn btn-success"
                                style={{ padding: '6px 12px', fontSize: '12px' }}
                                onClick={() => handleUpdateSaleStatus(sale.saleId, 'Completed')}
                              >
                                <Check size={12} />
                              </button>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            </div>
          </>
        )}
      </div>

      {showProductModal && (
        <div className="modal-overlay" onClick={() => setShowProductModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editingProduct ? 'Edit Product' : 'Create New Product'}</h2>
              <button className="modal-close" onClick={() => setShowProductModal(false)}>
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleProductSubmit}>
              <div className="form-group">
                <label>Product Name *</label>
                <input
                  type="text"
                  value={productForm.productName}
                  onChange={(e) => setProductForm({ ...productForm, productName: e.target.value })}
                  required
                />
              </div>

              <div className="form-group">
                <label>Description</label>
                <textarea
                  value={productForm.description}
                  onChange={(e) => setProductForm({ ...productForm, description: e.target.value })}
                  rows="4"
                />
              </div>

              <div className="form-group">
                <label>Price ($) *</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  value={productForm.price}
                  onChange={(e) => setProductForm({ ...productForm, price: e.target.value })}
                  required
                />
              </div>

              <div className="form-group">
                <label>Commission Percentage (%) *</label>
                <input
                  type="number"
                  step="0.01"
                  min="0"
                  max="100"
                  value={productForm.commissionPercentage}
                  onChange={(e) => setProductForm({ ...productForm, commissionPercentage: e.target.value })}
                  required
                />
              </div>

              <div className="modal-footer">
                <button type="button" className="btn btn-secondary" onClick={() => setShowProductModal(false)}>
                  Cancel
                </button>
                <button type="submit" className="btn btn-primary">
                  {editingProduct ? 'Update Product' : 'Create Product'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default AdminDashboard;
